<template>
  <div class="login-wrap">
    <!-- <div class="header flex">
        
        <span class="f14">注册</span>
      </div> -->
    <van-nav-bar
      title="登录"
      left-text="返回"
      right-text="注册"
      left-arrow
      @click-left="back"
    />
    <div class="logo">
      <img src="http://fresh.huruqing.cn/img/logo.adec77d3.png" alt="" />
    </div>
    <div class="form">
      <p class="phone flex jc-sb">
        <input required placeholder="请输入手机号" maxlength="11" v-model="phone" type="number" />
        <span @click="getCode" class="f12 f999">{{ text }}</span>
      </p>
      <p class="code mt-20">
        <input required placeholder="请输入验证码" v-model="smsCode" type="text" />
      </p>
      <button @click="login" class="f16" id="login-btn">短信登录</button>
    </div>
  </div>
</template>

<script>
import $axios from "@/utils/index";
export default {
  data() {
    return {
      phone: 13877776666,
      smsCode: null,
      text: "获取验证码",
      clickAble: "true",
      smsCode: null,
    };
  },
  computed:{
    // ...mapState(['phone','token'])
  },
  methods: {
    back() {
      this.$router.go(-1);
    },
    async getCode() {
      if (!this.clickAble) return false;
      this.clickAble = false;
      let res = await $axios.get("user/getSmsCode", { phone: this.phone });
      console.log(res);
      this.smsCode = res.smsCode;
      let count = 10;
      let timer = setInterval(() => {
        this.text = count--;
        if (count === 0) {
          clearInterval(timer);
          this.text = "重新获取";
          this.clickAble = true;
        }
      }, 1000);
    },
    async login() {
      try {
        let data = { phone: this.phone, smsCode: this.smsCode };
        let res = await $axios.post("user/login", data);
        console.log(res);

        this.$store.commit('updatePhone',this.phone)
        this.$store.commit('updateToken',res.result.token)
        // this.$store.commit('updateIsLogin',true)
        this.back()



      } catch (err) {
        console.log(err);
      }
    },
  },
};
</script>

<style lang="less">
.login-wrap {
  background-color: #fff;
  height: 100%;
  .logo {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 175px;
    img {
      width: 40%;
    }
  }
  .form {
    padding: 0 20px;
    p {
      width: 100%;
      border-bottom: 1px solid #f8f8f8;
      padding-bottom: 3px;
      align-items: baseline;
    }
    input {
      border: 0;
      outline: 0;
      font-size: 16px;
    }
    #login-btn {
      margin-top: 30px;
      margin-left: 15px;
      display: block;
      border: 0;
      outline: 0;
      color: #fff;
      width: 300px;
      height: 44px;
      background-color: #c03131;
      border: 1px solid #c03131;
    }
  }
}
</style>
